// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Stablecoin {
    uint256 public constant [[SLOT min_ratio]]; // 150%
    uint256 public constant PRICE = 2000e18;       // 1 ETH = $2000
    mapping(address => uint256) public collateral;
    mapping(address => uint256) public debt;

    error Undercollateralized();

    function mint(uint256 amount) external payable {
        collateral[msg.sender] += msg.value;
        debt[msg.sender] += amount;
        // collateralValueUsd = collateral * PRICE / 1e18
        // require collateralValueUsd * 10000 >= debt * MIN_RATIO_BPS
        uint256 collateralValueUsd = [[SLOT usd_value]];
        if ([[SLOT ratio_check]]) revert Undercollateralized();
    }

    function redeem(uint256 amount) external returns (uint256 ethReturned) {
        debt[msg.sender] -= amount;
        // ethReturned = amount / PRICE  (in 18-decimal terms)
        ethReturned = [[SLOT eth_calc]];
        collateral[msg.sender] -= ethReturned;
        (bool ok, ) = msg.sender.call{value: ethReturned}("");
        require(ok, "send fail");
    }

    receive() external payable {}
}
